module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    // SSOT fsm.control states: RESET, CLEAR, UPDATE, IDLE.
    localparam [1:0] RESET  = 2'd0,
                     CLEAR  = 2'd1,
                     UPDATE = 2'd2,
                     IDLE   = 2'd3;

    localparam integer SUM_W = COUNT_WIDTH + 1;

    logic [1:0] state;
    logic [1:0] next_state;

    // Functional-model state variables.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    // SSOT output-rule named observables mapped to DUT ports.
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    // Addition helper for FM_UPDATE: count + zero-extended step.
    logic [SUM_W-1:0] add_full;

    // Named handshake/ordering helper for cycle_model.handshake_rules.clear_enable_priority.
    logic clear_enable_priority;

    assign clear_enable_priority = (clear == 1'b1);
    assign add_full              = {1'b0, count_q} + {{(SUM_W-STEP_WIDTH){1'b0}}, step};

    // OUT_* mirrors architectural outputs and provides explicit SSOT trace points.
    assign out_count   = count_q;
    assign out_wrapped = wrapped_q;
    assign out_valid   = valid_q;

    // Top-level output mapping from SSOT out_* observables.
    assign count   = out_count;
    assign wrapped = out_wrapped;
    assign valid   = out_valid;

    // Conventional next-state decode for SSOT transitions.
    always @(*) begin
        next_state = state;
        case (state)
            RESET: begin
                if (rst_n == 1'b1) begin
                    next_state = IDLE;
                end else begin
                    next_state = RESET;
                end
            end

            IDLE: begin
                if (clear_enable_priority) begin
                    next_state = CLEAR;
                end else if (enable == 1'b1) begin
                    next_state = UPDATE;
                end else begin
                    next_state = IDLE;
                end
            end

            UPDATE: begin
                // SSOT transition: UPDATE -> IDLE on next cycle.
                next_state = IDLE;
            end

            CLEAR: begin
                // SSOT transition: CLEAR -> IDLE on next cycle.
                next_state = IDLE;
            end

            default: begin
                next_state = RESET;
            end
        endcase
    end

    // SSOT latency=1 contract: commit clear/update/idle result on this sampled edge.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state     <= RESET;
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else begin
            state <= next_state;

            // FM_CLEAR has priority over FM_UPDATE when clear and enable are both sampled high.
            if (clear_enable_priority) begin
                count_q   <= {COUNT_WIDTH{1'b0}};
                wrapped_q <= 1'b0;
                valid_q   <= 1'b0;
            end else if (enable == 1'b1) begin
                // FM_UPDATE: modulo-2^COUNT_WIDTH count and one-cycle overflow/valid pulses.
                count_q   <= add_full[COUNT_WIDTH-1:0];
                wrapped_q <= add_full[COUNT_WIDTH];
                valid_q   <= 1'b1;
            end else begin
                // FM_IDLE: hold count, deassert pulse outputs.
                count_q   <= count_q;
                wrapped_q <= 1'b0;
                valid_q   <= 1'b0;
            end
        end
    end

endmodule

